// ============ MIC DETECTION ============
let micActive = false;
let micVolume = 0;
let micSmooth = 0;
let micInited = false;
let micWasTalking = false;
const MIC_THRESHOLD = 0.015;

const birdImg = new Image();
birdImg.src = "data:image/png;base64,";

let micReady = false;
birdImg.onload = () => { micReady = true; };

const huhSound = new Audio("data:audio/wav;base64,");
huhSound.volume = 0.7;

function playHuh() {
  huhSound.currentTime = 0;
  huhSound.play().catch(()=>{});
}

function initMic() {
  if(micInited) return;
  micInited = true;
  navigator.mediaDevices.getUserMedia({ audio: true }).then(stream => {
    const audioCtx = new AudioContext();
    const src = audioCtx.createMediaStreamSource(stream);
    const analyser = audioCtx.createAnalyser();
    analyser.fftSize = 256;
    analyser.smoothingTimeConstant = 0.5;
    src.connect(analyser);
    const data = new Uint8Array(analyser.frequencyBinCount);

    function poll() {
      analyser.getByteFrequencyData(data);
      let sum = 0;
      for(let i = 0; i < data.length; i++) sum += data[i];
      micVolume = sum / data.length / 255;
      micSmooth = micSmooth * 0.7 + micVolume * 0.3;
      const nowTalking = micSmooth > MIC_THRESHOLD;
      if(nowTalking && !micWasTalking) {
        playHuh();
      }
      micWasTalking = nowTalking;
      micActive = nowTalking;
      requestAnimationFrame(poll);
    }
    poll();
    log("MIC ON — talk to trigger bird mode", true);
    toast("🎤 Mic connected! Talk to activate bird mode");
  }).catch(e => {
    micInited = false;
    log("Mic denied — will retry on next click", false);
  });
}

function tryMicOnce() {
  initMic();
  document.removeEventListener("click", tryMicOnce);
  document.removeEventListener("touchstart", tryMicOnce);
}
document.addEventListener("click", tryMicOnce);
document.addEventListener("touchstart", tryMicOnce);

function drawBird(time) {
  if(!micReady) return;
  const W = 200, H = 280;
  ctx.clearRect(0, 0, W, H);

  const shakeX = (Math.random() - 0.5) * micSmooth * 60;
  const shakeY = (Math.random() - 0.5) * micSmooth * 60;
  const scale = 1 + micSmooth * 0.15;
  const rot = Math.sin(time * 15) * micSmooth * 0.1;

  ctx.save();
  ctx.translate(W/2 + shakeX, H/2 + shakeY);
  ctx.rotate(rot);
  ctx.scale(scale, scale);

  const aspect = birdImg.width / birdImg.height;
  let drawW = 180, drawH = drawW / aspect;
  if(drawH > 240) { drawH = 240; drawW = drawH * aspect; }
  ctx.drawImage(birdImg, -drawW/2, -drawH/2, drawW, drawH);

  if(micSmooth > 0.05) {
    ctx.globalAlpha = micSmooth * 0.4;
    ctx.fillStyle = "#ff0000";
    ctx.fillRect(-drawW/2, -drawH/2, drawW, drawH);
    ctx.globalAlpha = 1;
  }
  ctx.restore();

  if(micSmooth > 0.08) {
    for(let i = 0; i < 3; i++) {
      const y = Math.random() * H;
      const h = 1 + Math.random() * 3;
      ctx.fillStyle = "rgba(57,255,20," + (micSmooth * 0.3) + ")";
      ctx.fillRect(Math.random() * 20 - 10, y, W, h);
    }
  }

  ctx.save();
  ctx.font = "bold 14px 'VT323', sans-serif";
  ctx.textAlign = "center";
  ctx.fillStyle = "rgba(57,255,20," + (0.5 + Math.sin(time * 8) * 0.5) + ")";
  ctx.fillText("🎤 LISTENING", W/2, H - 8);
  ctx.restore();
}
